{
  "name": "weekly-commit-monorepo",
  "version": "1.0.0",
  "private": true,
  "workspaces": [
    "frontend",
    "packages/shared"
  ],
  "scripts": {
    "lint": "npm run lint -w frontend && npm run lint -w @weekly-commit/shared && cd backend && ./gradlew spotlessCheck",
    "typecheck": "npm run typecheck -w frontend && npm run typecheck -w @weekly-commit/shared",
    "test": "npm run test -w frontend -- --run && npm run test -w @weekly-commit/shared -- --run && cd backend && ./gradlew test",
    "unit": "npm run test",
    "build": "npm run build -w @weekly-commit/shared && npm run build -w frontend && cd backend && ./gradlew build -x test"
  }
}

/**
 * Ticket API call functions built on top of the generic ApiClient.
 * Maps to TicketController backend endpoints.
 */

import type { ApiClient } from "./client.js";
import type {
  TicketResponse,
  TicketSummaryResponse,
  PagedTicketResponse,
  CreateTicketPayload,
  UpdateTicketPayload,
  TicketListParams,
  WeeklyPlanHistoryEntry,
  CarryForwardLineageResponse,
  TeamHistoryResponse,
} from "./ticketTypes.js";

export function createTicketApi(client: ApiClient, actorUserId: string) {
  const actorHeader = { "X-Actor-User-Id": actorUserId };

  return {
    /**
     * GET /api/tickets — paged list with optional filters.
     */
    listTickets: (params: TicketListParams = {}): Promise<PagedTicketResponse> => {
      const qs = new URLSearchParams();
      if (params.status) qs.set("status", params.status);
      if (params.assigneeUserId) qs.set("assigneeUserId", params.assigneeUserId);
      if (params.teamId) qs.set("teamId", params.teamId);
      if (params.rcdoNodeId) qs.set("rcdoNodeId", params.rcdoNodeId);
      if (params.targetWeek) qs.set("targetWeek", params.targetWeek);
      if (params.priority) qs.set("priority", params.priority);
      if (params.page != null) qs.set("page", String(params.page));
      if (params.pageSize != null) qs.set("pageSize", String(params.pageSize));
      if (params.sortBy) qs.set("sortBy", params.sortBy);
      if (params.sortDir) qs.set("sortDir", params.sortDir);
      const suffix = qs.toString() ? `?${qs.toString()}` : "";
      return client.get(`/tickets${suffix}`, { headers: actorHeader });
    },

    /** GET /api/tickets/{id} — full ticket detail. */
    getTicket: (ticketId: string): Promise<TicketResponse> =>
      client.get(`/tickets/${encodeURIComponent(ticketId)}`, {
        headers: actorHeader,
      }),

    /** POST /api/tickets — create a new ticket. */
    createTicket: (payload: CreateTicketPayload): Promise<TicketResponse> =>
      client.post("/tickets", payload, { headers: actorHeader }),

    /** PUT /api/tickets/{id} — partial update. */
    updateTicket: (
      ticketId: string,
      payload: UpdateTicketPayload,
    ): Promise<TicketResponse> =>
      client.put(`/tickets/${encodeURIComponent(ticketId)}`, payload, {
        headers: actorHeader,
      }),

    /** DELETE /api/tickets/{id} — soft-delete a ticket. */
    deleteTicket: (ticketId: string): Promise<void> =>
      client.delete(`/tickets/${encodeURIComponent(ticketId)}`, {
        headers: actorHeader,
      }),

    /**
     * POST /api/tickets/from-commit — create a ticket pre-populated from a commit.
     * The backend copies title, description, RCDO link, estimate, and reporterUserId.
     */
    createTicketFromCommit: (
      commitId: string,
      planId: string,
      overrides?: Partial<CreateTicketPayload>,
    ): Promise<TicketResponse> =>
      client.post(
        "/tickets/from-commit",
        { commitId, planId, ...overrides },
        { headers: actorHeader },
      ),

    // ── Plan history ──────────────────────────────────────────────────────────

    /**
     * GET /api/users/{userId}/plan-history
     * Returns week-by-week plan history for a user.
     */
    getPlanHistory: (userId: string): Promise<WeeklyPlanHistoryEntry[]> =>
      client.get(`/users/${encodeURIComponent(userId)}/plan-history`, {
        headers: actorHeader,
      }),

    // ── Carry-forward lineage ─────────────────────────────────────────────────

    /**
     * GET /api/commits/{commitId}/carry-forward-lineage
     * Returns the full carry-forward provenance chain for a commit.
     */
    getCarryForwardLineage: (
      commitId: string,
    ): Promise<CarryForwardLineageResponse> =>
      client.get(
        `/commits/${encodeURIComponent(commitId)}/carry-forward-lineage`,
        { headers: actorHeader },
      ),

    // ── Team history ──────────────────────────────────────────────────────────

    /**
     * GET /api/teams/{teamId}/history
     * Returns weekly trend data for the team.
     */
    getTeamHistory: (teamId: string): Promise<TeamHistoryResponse> =>
      client.get(`/teams/${encodeURIComponent(teamId)}/history`, {
        headers: actorHeader,
      }),

    /**
     * GET /api/tickets/summary — minimal list (no pagination) for quick selects.
     * Used for commit→ticket linking in forms.
     */
    listTicketSummaries: (
      teamId?: string,
    ): Promise<TicketSummaryResponse[]> => {
      const qs = teamId ? `?teamId=${encodeURIComponent(teamId)}` : "";
      return client.get(`/tickets/summaries${qs}`, { headers: actorHeader });
    },
  };
}

export type TicketApi = ReturnType<typeof createTicketApi>;

/**
 * TypeScript types for the Ticket API request/response payloads.
 * Mirror the backend DTO records from TicketController.
 */

import type { TicketStatus } from "./teamTypes.js";
import type { ChessPiece, EstimatePoints, CommitOutcome } from "./planTypes.js";

export type { TicketStatus };
export type TicketPriority = "CRITICAL" | "HIGH" | "MEDIUM" | "LOW";

/** Valid status transitions from a given status. */
export const TICKET_STATUS_TRANSITIONS: Record<TicketStatus, TicketStatus[]> = {
  TODO: ["IN_PROGRESS", "CANCELED"],
  IN_PROGRESS: ["DONE", "BLOCKED", "CANCELED", "TODO"],
  BLOCKED: ["IN_PROGRESS", "CANCELED", "TODO"],
  DONE: [],
  CANCELED: ["TODO"],
};

export const TICKET_STATUS_LABELS: Record<TicketStatus, string> = {
  TODO: "To Do",
  IN_PROGRESS: "In Progress",
  DONE: "Done",
  CANCELED: "Canceled",
  BLOCKED: "Blocked",
};

export const TICKET_PRIORITY_LABELS: Record<TicketPriority, string> = {
  CRITICAL: "Critical",
  HIGH: "High",
  MEDIUM: "Medium",
  LOW: "Low",
};

/** Single status history entry on a ticket. */
export interface TicketStatusHistory {
  readonly id: string;
  readonly ticketId: string;
  readonly fromStatus: TicketStatus | null;
  readonly toStatus: TicketStatus;
  readonly changedByUserId: string;
  readonly changedAt: string;
  readonly note: string | null;
}

/** A linked commit entry on a ticket detail. */
export interface LinkedCommitEntry {
  readonly commitId: string;
  readonly planId: string;
  readonly commitTitle: string;
  readonly chessPiece: ChessPiece;
  readonly estimatePoints: number | null;
  readonly weekStartDate: string;
  readonly outcome: CommitOutcome | null;
}

/** Full ticket detail response. Mirrors TicketResponse Java record. */
export interface TicketResponse {
  readonly id: string;
  readonly key: string;
  readonly title: string;
  readonly description: string | null;
  readonly status: TicketStatus;
  readonly priority: TicketPriority;
  readonly assigneeUserId: string | null;
  readonly reporterUserId: string;
  readonly teamId: string;
  readonly rcdoNodeId: string | null;
  readonly estimatePoints: EstimatePoints | null;
  readonly targetWeekStartDate: string | null;
  readonly statusHistory: TicketStatusHistory[];
  readonly linkedCommits: LinkedCommitEntry[];
  readonly createdAt: string;
  readonly updatedAt: string;
}

/** Compact ticket list item. Mirrors TicketSummary Java record. */
export interface TicketSummaryResponse {
  readonly id: string;
  readonly key: string;
  readonly title: string;
  readonly status: TicketStatus;
  readonly priority: TicketPriority;
  readonly assigneeUserId: string | null;
  readonly teamId: string;
  readonly rcdoNodeId: string | null;
  readonly estimatePoints: EstimatePoints | null;
  readonly targetWeekStartDate: string | null;
  readonly createdAt: string;
  readonly updatedAt: string;
}

/** Paginated ticket list. Mirrors PagedTicketResponse Java record. */
export interface PagedTicketResponse {
  readonly items: TicketSummaryResponse[];
  readonly total: number;
  readonly page: number;
  readonly pageSize: number;
}

/** POST /api/tickets request body. */
export interface CreateTicketPayload {
  readonly title: string;
  readonly description?: string;
  readonly status?: TicketStatus;
  readonly priority: TicketPriority;
  readonly assigneeUserId?: string;
  readonly reporterUserId: string;
  readonly teamId: string;
  readonly rcdoNodeId?: string;
  readonly estimatePoints?: EstimatePoints;
  readonly targetWeekStartDate?: string;
}

/** PUT /api/tickets/{id} request body — partial update. */
export interface UpdateTicketPayload {
  readonly title?: string;
  readonly description?: string;
  readonly status?: TicketStatus;
  readonly priority?: TicketPriority;
  readonly assigneeUserId?: string;
  readonly teamId?: string;
  readonly rcdoNodeId?: string;
  readonly estimatePoints?: EstimatePoints;
  readonly targetWeekStartDate?: string;
}

/** Query params for GET /api/tickets. */
export interface TicketListParams {
  readonly status?: TicketStatus;
  readonly assigneeUserId?: string;
  readonly teamId?: string;
  readonly rcdoNodeId?: string;
  readonly targetWeek?: string;
  readonly priority?: TicketPriority;
  readonly page?: number;
  readonly pageSize?: number;
  readonly sortBy?: "key" | "title" | "status" | "priority" | "updatedAt";
  readonly sortDir?: "asc" | "desc";
}

// ── Plan history types ──────────────────────────────────────────────────────

/** Per-week summary entry for plan history. Mirrors WeeklyPlanHistoryEntry Java record. */
export interface WeeklyPlanHistoryEntry {
  readonly planId: string;
  readonly weekStartDate: string;
  readonly planState: "DRAFT" | "LOCKED" | "RECONCILING" | "RECONCILED";
  readonly compliant: boolean;
  readonly commitCount: number;
  readonly plannedPoints: number;
  readonly achievedPoints: number;
  readonly carryForwardCount: number;
}

/** Carry-forward lineage node — one step in the provenance chain. */
export interface CarryForwardNode {
  readonly commitId: string;
  readonly planId: string;
  readonly weekStartDate: string;
  readonly title: string;
  readonly outcome: CommitOutcome | null;
  readonly streak: number;
}

/** Full carry-forward lineage chain. Mirrors CarryForwardLineageResponse Java record. */
export interface CarryForwardLineageResponse {
  readonly currentCommitId: string;
  readonly chain: CarryForwardNode[];
}

// ── Team history types ──────────────────────────────────────────────────────

/** One row in the team history trend table. Mirrors TeamWeekHistoryEntry Java record. */
export interface TeamWeekHistoryEntry {
  readonly weekStartDate: string;
  readonly memberCount: number;
  readonly complianceRate: number;
  readonly plannedPoints: number;
  readonly achievedPoints: number;
  readonly carryForwardRate: number;
  readonly exceptionCount: number;
}

/** Team history response. Mirrors TeamHistoryResponse Java record. */
export interface TeamHistoryResponse {
  readonly teamId: string;
  readonly entries: TeamWeekHistoryEntry[];
}

// ── Filter preset types ──────────────────────────────────────────────────────

/** A saved filter preset. */
export interface FilterPreset {
  readonly id: string;
  readonly name: string;
  readonly params: Record<string, string>;
}

/**
 * React hooks for Ticket, Plan-history, and Team-history data fetching.
 */

import { useMemo } from "react";
import { useHostBridge } from "../host/HostProvider.js";
import { createApiClient } from "./client.js";
import { useQuery, type QueryState } from "./hooks.js";
import { createTicketApi, type TicketApi } from "./ticketApi.js";
import type {
  PagedTicketResponse,
  TicketResponse,
  TicketListParams,
  WeeklyPlanHistoryEntry,
  CarryForwardLineageResponse,
  TeamHistoryResponse,
} from "./ticketTypes.js";

/**
 * Returns a stable TicketApi instance bound to the current user's auth token.
 */
export function useTicketApi(): TicketApi {
  const bridge = useHostBridge();
  const { authToken, authenticatedUser } = bridge.context;
  return useMemo(
    () => {
      const client = createApiClient({
        baseUrl: "/api",
        getAuthToken: () => bridge.context.authToken,
      });
      return createTicketApi(client, authenticatedUser.id);
    },
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [authToken, authenticatedUser.id],
  );
}

/**
 * Fetches a paged ticket list with optional filters.
 * The params object is serialized as the cache key.
 */
export function useTicketList(
  params: TicketListParams = {},
): QueryState<PagedTicketResponse> {
  const api = useTicketApi();
  const key = `tickets-${JSON.stringify(params)}`;
  return useQuery<PagedTicketResponse>(key, () => api.listTickets(params));
}

/**
 * Fetches full ticket detail for a single ticket.
 * Returns null data when ticketId is null.
 */
export function useTicket(
  ticketId: string | null,
): QueryState<TicketResponse | null> {
  const api = useTicketApi();
  const key = `ticket-${ticketId ?? "none"}`;
  return useQuery<TicketResponse | null>(
    key,
    () => (ticketId ? api.getTicket(ticketId) : Promise.resolve(null)),
    { enabled: ticketId !== null },
  );
}

/**
 * Fetches the week-by-week plan history for a user.
 */
export function usePlanHistory(
  userId: string | null,
): QueryState<WeeklyPlanHistoryEntry[]> {
  const api = useTicketApi();
  const key = `plan-history-${userId ?? "none"}`;
  return useQuery<WeeklyPlanHistoryEntry[]>(
    key,
    () => (userId ? api.getPlanHistory(userId) : Promise.resolve([])),
    { enabled: userId !== null },
  );
}

/**
 * Fetches the carry-forward lineage for a commit.
 */
export function useCarryForwardLineage(
  commitId: string | null,
): QueryState<CarryForwardLineageResponse | null> {
  const api = useTicketApi();
  const key = `cf-lineage-${commitId ?? "none"}`;
  return useQuery<CarryForwardLineageResponse | null>(
    key,
    () =>
      commitId
        ? api.getCarryForwardLineage(commitId)
        : Promise.resolve(null),
    { enabled: commitId !== null },
  );
}

/**
 * Fetches the weekly trend history for a team.
 */
export function useTeamHistory(
  teamId: string | null,
): QueryState<TeamHistoryResponse | null> {
  const api = useTicketApi();
  const key = `team-history-${teamId ?? "none"}`;
  return useQuery<TeamHistoryResponse | null>(
    key,
    () => (teamId ? api.getTeamHistory(teamId) : Promise.resolve(null)),
    { enabled: teamId !== null },
  );
}

/**
 * Tickets page — native ticket management.
 * Route: /weekly/tickets and /weekly/tickets/:ticketId
 *
 * Features:
 *   - TicketListView with sortable columns and pagination.
 *   - Filter bar: status, assignee, team, RCDO, target week, priority.
 *   - Filters persisted in URL params.
 *   - Create ticket button → TicketForm modal.
 *   - Click on a ticket row → TicketDetailView panel.
 *   - TicketDetailView: status transitions, assignment change, history timeline.
 *   - Create-from-commit: pre-fills TicketForm from commit fields.
 */
import { useState, useCallback, useMemo } from "react";
import { useSearchParams } from "react-router-dom";
import { useHostBridge } from "../host/HostProvider.js";
import { useTicketList, useTicketApi, useTicket } from "../api/ticketHooks.js";
import { useRcdoTree } from "../api/rcdoHooks.js";
import { TicketListView, type TicketSortColumn } from "../components/tickets/TicketListView.js";
import { TicketForm } from "../components/tickets/TicketForm.js";
import { TicketDetailView } from "../components/tickets/TicketDetailView.js";
import type {
  TicketListParams,
  TicketStatus,
  TicketPriority,
  CreateTicketPayload,
} from "../api/ticketTypes.js";
import { TICKET_STATUS_LABELS, TICKET_PRIORITY_LABELS } from "../api/ticketTypes.js";

const TICKET_STATUSES: TicketStatus[] = [
  "TODO",
  "IN_PROGRESS",
  "BLOCKED",
  "DONE",
  "CANCELED",
];
const TICKET_PRIORITIES: TicketPriority[] = [
  "CRITICAL",
  "HIGH",
  "MEDIUM",
  "LOW",
];

const PAGE_SIZE = 20;

// ── URL ↔ filter helpers ──────────────────────────────────────────────────────

function paramsToListParams(
  sp: URLSearchParams,
): TicketListParams & {
  sortBy: TicketSortColumn;
  sortDir: "asc" | "desc";
  page: number;
} {
  const status = sp.get("status") as TicketStatus | null;
  const assignee = sp.get("assignee");
  const team = sp.get("team");
  const rcdo = sp.get("rcdo");
  const week = sp.get("week");
  const priority = sp.get("priority") as TicketPriority | null;
  return {
    ...(status ? { status } : {}),
    ...(assignee ? { assigneeUserId: assignee } : {}),
    ...(team ? { teamId: team } : {}),
    ...(rcdo ? { rcdoNodeId: rcdo } : {}),
    ...(week ? { targetWeek: week } : {}),
    ...(priority ? { priority } : {}),
    page: sp.get("page") ? Number(sp.get("page")) : 1,
    pageSize: PAGE_SIZE,
    sortBy: (sp.get("sortBy") as TicketSortColumn | null) ?? "updatedAt",
    sortDir: sp.get("sortDir") === "asc" ? "asc" : "desc",
  };
}

function buildRcdoLabels(
  nodes: ReturnType<typeof useRcdoTree>["data"],
): Record<string, string> {
  const map: Record<string, string> = {};
  function traverse(
    ns: typeof nodes,
    path: string[] = [],
  ) {
    if (!ns) return;
    for (const n of ns) {
      const nextPath = [...path, n.title];
      map[n.id] = nextPath.join(" > ");
      traverse(n.children, nextPath);
    }
  }
  traverse(nodes ?? []);
  return map;
}

// ── Filter controls ───────────────────────────────────────────────────────────

const inputStyle: React.CSSProperties = {
  padding: "0.35rem 0.6rem",
  border: "1px solid var(--color-border)",
  borderRadius: "var(--border-radius)",
  background: "var(--color-surface)",
  color: "var(--color-text)",
  fontFamily: "inherit",
  fontSize: "0.8rem",
};

function TicketFilters({
  params,
  onParamsChange,
  onClearFilters,
}: {
  readonly params: ReturnType<typeof paramsToListParams>;
  readonly onParamsChange: (patch: Partial<ReturnType<typeof paramsToListParams>>) => void;
  readonly onClearFilters: () => void;
}) {
  const hasFilter =
    params.status ??
    params.assigneeUserId ??
    params.teamId ??
    params.rcdoNodeId ??
    params.targetWeek ??
    params.priority;

  return (
    <div
      data-testid="ticket-filters"
      style={{
        background: "var(--color-surface)",
        border: "1px solid var(--color-border)",
        borderRadius: "var(--border-radius)",
        padding: "0.75rem 1rem",
        display: "flex",
        gap: "0.625rem",
        flexWrap: "wrap",
        alignItems: "flex-end",
      }}
    >
      {/* Status */}
      <div style={{ display: "flex", flexDirection: "column", gap: "2px" }}>
        <label
          htmlFor="tf-status-filter"
          style={{ fontSize: "0.7rem", fontWeight: 700, color: "var(--color-text-muted)", textTransform: "uppercase" }}
        >
          Status
        </label>
        <select
          id="tf-status-filter"
          value={params.status ?? ""}
          onChange={(e) => {
            const v = e.target.value as TicketStatus | "";
            onParamsChange({ ...(v ? { status: v } : {}), page: 1 });
          }}
          data-testid="filter-status"
          style={inputStyle}
        >
          <option value="">All statuses</option>
          {TICKET_STATUSES.map((s) => (
            <option key={s} value={s}>
              {TICKET_STATUS_LABELS[s]}
            </option>
          ))}
        </select>
      </div>

      {/* Priority */}
      <div style={{ display: "flex", flexDirection: "column", gap: "2px" }}>
        <label
          htmlFor="tf-priority-filter"
          style={{ fontSize: "0.7rem", fontWeight: 700, color: "var(--color-text-muted)", textTransform: "uppercase" }}
        >
          Priority
        </label>
        <select
          id="tf-priority-filter"
          value={params.priority ?? ""}
          onChange={(e) => {
            const v = e.target.value as TicketPriority | "";
            onParamsChange({ ...(v ? { priority: v } : {}), page: 1 });
          }}
          data-testid="filter-priority"
          style={inputStyle}
        >
          <option value="">All priorities</option>
          {TICKET_PRIORITIES.map((p) => (
            <option key={p} value={p}>
              {TICKET_PRIORITY_LABELS[p]}
            </option>
          ))}
        </select>
      </div>

      {/* Assignee */}
      <div style={{ display: "flex", flexDirection: "column", gap: "2px" }}>
        <label
          htmlFor="tf-assignee-filter"
          style={{ fontSize: "0.7rem", fontWeight: 700, color: "var(--color-text-muted)", textTransform: "uppercase" }}
        >
          Assignee
        </label>
        <input
          id="tf-assignee-filter"
          type="text"
          placeholder="User ID…"
          value={params.assigneeUserId ?? ""}
          onChange={(e) => {
            const v = e.target.value;
            onParamsChange({ ...(v ? { assigneeUserId: v } : {}), page: 1 });
          }}
          data-testid="filter-assignee"
          style={{ ...inputStyle, minWidth: "110px" }}
        />
      </div>

      {/* Team */}
      <div style={{ display: "flex", flexDirection: "column", gap: "2px" }}>
        <label
          htmlFor="tf-team-filter"
          style={{ fontSize: "0.7rem", fontWeight: 700, color: "var(--color-text-muted)", textTransform: "uppercase" }}
        >
          Team
        </label>
        <input
          id="tf-team-filter"
          type="text"
          placeholder="Team ID…"
          value={params.teamId ?? ""}
          onChange={(e) => {
            const v = e.target.value;
            onParamsChange({ ...(v ? { teamId: v } : {}), page: 1 });
          }}
          data-testid="filter-team"
          style={{ ...inputStyle, minWidth: "110px" }}
        />
      </div>

      {/* RCDO */}
      <div style={{ display: "flex", flexDirection: "column", gap: "2px" }}>
        <label
          htmlFor="tf-rcdo-filter"
          style={{ fontSize: "0.7rem", fontWeight: 700, color: "var(--color-text-muted)", textTransform: "uppercase" }}
        >
          RCDO
        </label>
        <input
          id="tf-rcdo-filter"
          type="text"
          placeholder="RCDO node ID…"
          value={params.rcdoNodeId ?? ""}
          onChange={(e) => {
            const v = e.target.value;
            onParamsChange({ ...(v ? { rcdoNodeId: v } : {}), page: 1 });
          }}
          data-testid="filter-rcdo"
          style={{ ...inputStyle, minWidth: "110px" }}
        />
      </div>

      {/* Target Week */}
      <div style={{ display: "flex", flexDirection: "column", gap: "2px" }}>
        <label
          htmlFor="tf-week-filter"
          style={{ fontSize: "0.7rem", fontWeight: 700, color: "var(--color-text-muted)", textTransform: "uppercase" }}
        >
          Target Week
        </label>
        <input
          id="tf-week-filter"
          type="date"
          value={params.targetWeek ?? ""}
          onChange={(e) => {
            const v = e.target.value;
            onParamsChange({ ...(v ? { targetWeek: v } : {}), page: 1 });
          }}
          data-testid="filter-week"
          style={inputStyle}
        />
      </div>

      {/* Clear all */}
      {hasFilter && (
        <button
          type="button"
          onClick={onClearFilters}
          data-testid="filter-clear-all"
          style={{
            padding: "0.35rem 0.75rem",
            border: "1px solid var(--color-border)",
            borderRadius: "var(--border-radius)",
            background: "var(--color-surface)",
            cursor: "pointer",
            fontFamily: "inherit",
            fontSize: "0.8rem",
            alignSelf: "flex-end",
          }}
        >
          ✕ Clear all
        </button>
      )}
    </div>
  );
}

// ── Tickets page ──────────────────────────────────────────────────────────────

export default function Tickets() {
  const bridge = useHostBridge();
  const currentUserId = bridge.context.authenticatedUser.id;
  const currentTeamId = bridge.context.currentTeam?.id;

  const [searchParams, setSearchParams] = useSearchParams();
  const listParams = useMemo(
    () => paramsToListParams(searchParams),
    [searchParams],
  );

  const { data: rcdoTreeData } = useRcdoTree();
  const rcdoLabels = useMemo(
    () => buildRcdoLabels(rcdoTreeData),
    [rcdoTreeData],
  );

  // Fetch ticket list
  const {
    data: ticketPage,
    loading: ticketsLoading,
    refetch: refetchTickets,
  } = useTicketList(listParams);

  const ticketApi = useTicketApi();

  // Selected ticket for detail view
  const [selectedTicketId, setSelectedTicketId] = useState<string | null>(null);
  const {
    data: ticketDetail,
    loading: detailLoading,
    refetch: refetchDetail,
  } = useTicket(selectedTicketId);

  // Form state
  type FormMode = "create" | "create-from-commit" | null;
  const [formMode, setFormMode] = useState<FormMode>(null);
  const [formInitialValues, setFormInitialValues] = useState<
    Partial<CreateTicketPayload>
  >({});

  // ── Param update helper ──────────────────────────────────────────────────

  const updateParams = useCallback(
    (patch: Partial<ReturnType<typeof paramsToListParams>>) => {
      setSearchParams((prev) => {
        const next = new URLSearchParams(prev);
        const merged = { ...paramsToListParams(prev), ...patch };
        const pairs: [string, string][] = [
          ...(merged.status ? [["status", merged.status] as [string, string]] : []),
          ...(merged.assigneeUserId ? [["assignee", merged.assigneeUserId] as [string, string]] : []),
          ...(merged.teamId ? [["team", merged.teamId] as [string, string]] : []),
          ...(merged.rcdoNodeId ? [["rcdo", merged.rcdoNodeId] as [string, string]] : []),
          ...(merged.targetWeek ? [["week", merged.targetWeek] as [string, string]] : []),
          ...(merged.priority ? [["priority", merged.priority] as [string, string]] : []),
          ...(merged.page && merged.page !== 1 ? [["page", String(merged.page)] as [string, string]] : []),
          ...(merged.sortBy && merged.sortBy !== "updatedAt" ? [["sortBy", merged.sortBy] as [string, string]] : []),
          ...(merged.sortDir && merged.sortDir !== "desc" ? [["sortDir", merged.sortDir] as [string, string]] : []),
        ];
        // Start fresh
        Array.from(next.keys()).forEach((k) => next.delete(k));
        pairs.forEach(([k, v]) => next.set(k, v));
        return next;
      });
    },
    [setSearchParams],
  );

  // ── Create ticket handler ────────────────────────────────────────────────

  const handleCreateTicket = useCallback(
    async (payload: CreateTicketPayload) => {
      await ticketApi.createTicket(payload);
      setFormMode(null);
      setFormInitialValues({});
      refetchTickets();
    },
    [ticketApi, refetchTickets],
  );

  // ── Status transition ────────────────────────────────────────────────────

  const handleStatusTransition = useCallback(
    async (ticketId: string, newStatus: TicketStatus) => {
      await ticketApi.updateTicket(ticketId, { status: newStatus });
      refetchDetail();
      refetchTickets();
    },
    [ticketApi, refetchDetail, refetchTickets],
  );

  // ── Assignment change ────────────────────────────────────────────────────

  const handleAssigneeChange = useCallback(
    async (ticketId: string, assigneeUserId: string) => {
      await ticketApi.updateTicket(
        ticketId,
        assigneeUserId
          ? { assigneeUserId }
          : {},
      );
      refetchDetail();
      refetchTickets();
    },
    [ticketApi, refetchDetail, refetchTickets],
  );

  const btnPrimary: React.CSSProperties = {
    padding: "0.5rem 1rem",
    border: "none",
    borderRadius: "var(--border-radius)",
    background: "var(--color-primary)",
    color: "#fff",
    cursor: "pointer",
    fontFamily: "inherit",
    fontSize: "0.875rem",
    fontWeight: 600,
  };

  return (
    <div
      className="route-page"
      data-testid="page-tickets"
      style={{ display: "flex", flexDirection: "column", gap: "1rem" }}
    >
      {/* Page header */}
      <div
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          flexWrap: "wrap",
          gap: "0.5rem",
        }}
      >
        <h2 style={{ margin: 0, fontSize: "1.25rem" }}>Tickets</h2>
        <button
          type="button"
          style={btnPrimary}
          onClick={() => {
            setFormInitialValues({
              reporterUserId: currentUserId,
              ...(currentTeamId ? { teamId: currentTeamId } : {}),
            });
            setFormMode("create");
          }}
          data-testid="create-ticket-btn"
        >
          + Create Ticket
        </button>
      </div>

      {/* Filters */}
      <TicketFilters
        params={listParams}
        onParamsChange={updateParams}
        onClearFilters={() => setSearchParams(new URLSearchParams())}
      />

      {/* Ticket count summary */}
      {ticketPage && (
        <div
          data-testid="ticket-count"
          style={{ fontSize: "0.85rem", color: "var(--color-text-muted)" }}
        >
          {ticketPage.total} ticket{ticketPage.total !== 1 ? "s" : ""}
        </div>
      )}

      {/* Main content: list + optional detail panel */}
      <div
        style={{
          display: "flex",
          gap: "1rem",
          alignItems: "flex-start",
          flexWrap: selectedTicketId ? "nowrap" : "wrap",
        }}
      >
        {/* Ticket list */}
        <div
          style={{
            flex: selectedTicketId ? "0 0 55%" : "1 1 100%",
            minWidth: 0,
          }}
        >
          <TicketListView
            tickets={ticketPage?.items ?? []}
            total={ticketPage?.total ?? 0}
            page={listParams.page ?? 1}
            pageSize={PAGE_SIZE}
            sortBy={listParams.sortBy}
            sortDir={listParams.sortDir}
            loading={ticketsLoading}
            onPageChange={(p) => updateParams({ page: p })}
            onSortChange={(col, dir) => updateParams({ sortBy: col, sortDir: dir })}
            onSelectTicket={(id) =>
              setSelectedTicketId(id === selectedTicketId ? null : id)
            }
            rcdoLabels={rcdoLabels}
          />
        </div>

        {/* Detail panel */}
        {selectedTicketId && (
          <div
            data-testid="ticket-detail-panel"
            style={{
              flex: "1 1 42%",
              minWidth: "280px",
              position: "sticky",
              top: "1rem",
            }}
          >
            {detailLoading && (
              <div
                data-testid="ticket-detail-loading"
                role="status"
                style={{ color: "var(--color-text-muted)", padding: "1rem" }}
              >
                Loading…
              </div>
            )}
            {!detailLoading && ticketDetail && (
              <TicketDetailView
                ticket={ticketDetail}
                onStatusTransition={handleStatusTransition}
                onAssigneeChange={handleAssigneeChange}
                {...(ticketDetail.rcdoNodeId && rcdoLabels[ticketDetail.rcdoNodeId]
                  ? { rcdoPath: rcdoLabels[ticketDetail.rcdoNodeId] }
                  : {})}
                onClose={() => setSelectedTicketId(null)}
                onEdit={() => {
                  setFormInitialValues({
                    title: ticketDetail.title,
                    ...(ticketDetail.description ? { description: ticketDetail.description } : {}),
                    status: ticketDetail.status,
                    priority: ticketDetail.priority,
                    ...(ticketDetail.assigneeUserId ? { assigneeUserId: ticketDetail.assigneeUserId } : {}),
                    reporterUserId: ticketDetail.reporterUserId,
                    teamId: ticketDetail.teamId,
                    ...(ticketDetail.rcdoNodeId ? { rcdoNodeId: ticketDetail.rcdoNodeId } : {}),
                    ...(ticketDetail.estimatePoints != null ? { estimatePoints: ticketDetail.estimatePoints } : {}),
                    ...(ticketDetail.targetWeekStartDate ? { targetWeekStartDate: ticketDetail.targetWeekStartDate } : {}),
                  });
                  setFormMode("create"); // re-uses the form for editing
                }}
              />
            )}
          </div>
        )}
      </div>

      {/* Create Ticket form modal */}
      {formMode !== null && (
        <TicketForm
          mode="create"
          initialValues={formInitialValues}
          currentUserId={currentUserId}
          {...(currentTeamId ? { currentTeamId } : {})}
          onSubmit={handleCreateTicket}
          onCancel={() => {
            setFormMode(null);
            setFormInitialValues({});
          }}
        />
      )}
    </div>
  );
}

package com.weeklycommit.ticket.controller;

import com.weeklycommit.ticket.dto.CreateTicketRequest;
import com.weeklycommit.ticket.dto.LinkTicketRequest;
import com.weeklycommit.ticket.dto.LinkTicketResponse;
import com.weeklycommit.ticket.dto.TicketResponse;
import com.weeklycommit.ticket.dto.TicketStatusHistoryResponse;
import com.weeklycommit.ticket.dto.UpdateTicketRequest;
import com.weeklycommit.ticket.dto.UpdateTicketStatusRequest;
import com.weeklycommit.ticket.service.LinkTicketService;
import com.weeklycommit.ticket.service.TicketService;
import jakarta.validation.Valid;
import java.util.List;
import java.util.UUID;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.DeleteMapping;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.PutMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;

/**
 * REST endpoints for native ticket (work item) management.
 *
 * <ul>
 * <li>{@code GET  /api/tickets?teamId=…} — list tickets for a team</li>
 * <li>{@code POST /api/tickets} — create a ticket</li>
 * <li>{@code GET /api/tickets/{id}} — get a ticket</li>
 * <li>{@code PUT /api/tickets/{id}} — update a ticket</li>
 * <li>{@code DELETE /api/tickets/{id}} — delete a ticket</li>
 * <li>{@code PUT /api/tickets/{id}/status} — transition ticket status</li>
 * <li>{@code GET /api/tickets/{id}/history} — status history</li>
 * <li>{@code PUT /api/plans/{planId}/commits/{commitId}/link-ticket} — link
 * ticket to commit</li>
 * </ul>
 */
@RestController
public class TicketController {

	private final TicketService ticketService;
	private final LinkTicketService linkTicketService;

	public TicketController(TicketService ticketService, LinkTicketService linkTicketService) {
		this.ticketService = ticketService;
		this.linkTicketService = linkTicketService;
	}

	// -------------------------------------------------------------------------
	// Ticket CRUD
	// -------------------------------------------------------------------------

	/** List all tickets for a team. */
	@GetMapping("/api/tickets")
	public ResponseEntity<List<TicketResponse>> listTickets(@RequestParam UUID teamId) {
		return ResponseEntity.ok(ticketService.listTicketsByTeam(teamId));
	}

	/** Create a new ticket. */
	@PostMapping("/api/tickets")
	public ResponseEntity<TicketResponse> createTicket(@Valid @RequestBody CreateTicketRequest request) {
		return ResponseEntity.status(HttpStatus.CREATED).body(ticketService.createTicket(request));
	}

	/** Get a single ticket. */
	@GetMapping("/api/tickets/{id}")
	public ResponseEntity<TicketResponse> getTicket(@PathVariable UUID id) {
		return ResponseEntity.ok(ticketService.getTicket(id));
	}

	/** Partially update a ticket. */
	@PutMapping("/api/tickets/{id}")
	public ResponseEntity<TicketResponse> updateTicket(@PathVariable UUID id,
			@RequestBody UpdateTicketRequest request) {
		return ResponseEntity.ok(ticketService.updateTicket(id, request));
	}

	/** Delete a ticket. */
	@DeleteMapping("/api/tickets/{id}")
	public ResponseEntity<Void> deleteTicket(@PathVariable UUID id) {
		ticketService.deleteTicket(id);
		return ResponseEntity.noContent().build();
	}

	// -------------------------------------------------------------------------
	// Status transition
	// -------------------------------------------------------------------------

	/** Transition a ticket's status. */
	@PutMapping("/api/tickets/{id}/status")
	public ResponseEntity<TicketResponse> updateStatus(@PathVariable UUID id,
			@Valid @RequestBody UpdateTicketStatusRequest request) {
		return ResponseEntity.ok(ticketService.updateStatus(id, request.status(), request.changedByUserId()));
	}

	// -------------------------------------------------------------------------
	// Status history
	// -------------------------------------------------------------------------

	/** Retrieve the full status-change history for a ticket. */
	@GetMapping("/api/tickets/{id}/history")
	public ResponseEntity<List<TicketStatusHistoryResponse>> getStatusHistory(@PathVariable UUID id) {
		return ResponseEntity.ok(ticketService.getStatusHistory(id));
	}

	// -------------------------------------------------------------------------
	// Link ticket to commit
	// -------------------------------------------------------------------------

	/**
	 * Links a ticket to a commit. Enforces RCDO defaulting and duplicate-link
	 * prevention.
	 */
	@PutMapping("/api/plans/{planId}/commits/{commitId}/link-ticket")
	public ResponseEntity<LinkTicketResponse> linkTicket(@PathVariable UUID planId, @PathVariable UUID commitId,
			@Valid @RequestBody LinkTicketRequest request) {
		return ResponseEntity.ok(linkTicketService.linkTicket(planId, commitId, request.workItemId()));
	}
}

package com.weeklycommit.ticket.dto;

import com.weeklycommit.domain.entity.WorkItem;
import com.weeklycommit.domain.enums.TicketStatus;
import java.time.Instant;
import java.time.LocalDate;
import java.util.UUID;

/**
 * Immutable view of a work item (ticket).
 */
public record TicketResponse(UUID id, UUID teamId, String key, String title, String description, TicketStatus status,
		UUID assigneeUserId, UUID reporterUserId, Integer estimatePoints, UUID rcdoNodeId,
		LocalDate targetWeekStartDate, Instant createdAt, Instant updatedAt) {

	public static TicketResponse from(WorkItem item) {
		return new TicketResponse(item.getId(), item.getTeamId(), item.getKey(), item.getTitle(), item.getDescription(),
				item.getStatus(), item.getAssigneeUserId(), item.getReporterUserId(), item.getEstimatePoints(),
				item.getRcdoNodeId(), item.getTargetWeekStartDate(), item.getCreatedAt(), item.getUpdatedAt());
	}
}

/**
 * TicketListView — sortable, paginated table of tickets.
 *
 * Columns: key, title, status, assignee, team, priority, RCDO, target week.
 * Filters are applied externally (passed via props from Tickets route).
 * Sortable columns trigger `onSortChange`.
 */
import type {
  TicketSummaryResponse,
  TicketStatus,
  TicketPriority,
} from "../../api/ticketTypes.js";
import {
  TICKET_STATUS_LABELS,
  TICKET_PRIORITY_LABELS,
} from "../../api/ticketTypes.js";

export type TicketSortColumn =
  | "key"
  | "title"
  | "status"
  | "priority"
  | "updatedAt";

export interface TicketListViewProps {
  readonly tickets: TicketSummaryResponse[];
  readonly total: number;
  readonly page: number;
  readonly pageSize: number;
  readonly sortBy: TicketSortColumn;
  readonly sortDir: "asc" | "desc";
  readonly loading: boolean;
  readonly onPageChange: (page: number) => void;
  readonly onSortChange: (col: TicketSortColumn, dir: "asc" | "desc") => void;
  readonly onSelectTicket: (ticketId: string) => void;
  /** Labels for RCDO nodes by id. */
  readonly rcdoLabels?: Record<string, string>;
}

const STATUS_BADGE_STYLES: Record<TicketStatus, React.CSSProperties> = {
  TODO: { background: "#f1f5f9", color: "#475569" },
  IN_PROGRESS: { background: "#dbeafe", color: "#1e40af" },
  DONE: { background: "#d1fae5", color: "#065f46" },
  CANCELED: { background: "#f1f5f9", color: "#94a3b8" },
  BLOCKED: { background: "#fee2e2", color: "#991b1b" },
};

const PRIORITY_BADGE_STYLES: Record<TicketPriority, React.CSSProperties> = {
  CRITICAL: { background: "#fee2e2", color: "#991b1b", fontWeight: 700 },
  HIGH: { background: "#fef3c7", color: "#92400e" },
  MEDIUM: { background: "#eff6ff", color: "#1e40af" },
  LOW: { background: "#f1f5f9", color: "#475569" },
};

function StatusBadge({ status }: { readonly status: TicketStatus }) {
  return (
    <span
      style={{
        ...STATUS_BADGE_STYLES[status],
        padding: "2px 8px",
        borderRadius: "999px",
        fontSize: "0.7rem",
        fontWeight: 600,
        display: "inline-block",
        whiteSpace: "nowrap",
      }}
    >
      {TICKET_STATUS_LABELS[status]}
    </span>
  );
}

function PriorityBadge({ priority }: { readonly priority: TicketPriority }) {
  return (
    <span
      style={{
        ...PRIORITY_BADGE_STYLES[priority],
        padding: "2px 8px",
        borderRadius: "999px",
        fontSize: "0.7rem",
        display: "inline-block",
        whiteSpace: "nowrap",
      }}
    >
      {TICKET_PRIORITY_LABELS[priority]}
    </span>
  );
}

function SortIndicator({
  col,
  active,
  dir,
}: {
  readonly col: TicketSortColumn;
  readonly active: boolean;
  readonly dir: "asc" | "desc";
}) {
  void col;
  if (!active) return <span style={{ opacity: 0.3 }}>↕</span>;
  return <span>{dir === "asc" ? "↑" : "↓"}</span>;
}

const SORTABLE_COLUMNS: { col: TicketSortColumn; label: string }[] = [
  { col: "key", label: "Key" },
  { col: "title", label: "Title" },
  { col: "status", label: "Status" },
  { col: "priority", label: "Priority" },
  { col: "updatedAt", label: "Updated" },
];

export function TicketListView({
  tickets,
  total,
  page,
  pageSize,
  sortBy,
  sortDir,
  loading,
  onPageChange,
  onSortChange,
  onSelectTicket,
  rcdoLabels = {},
}: TicketListViewProps) {
  const totalPages = Math.max(1, Math.ceil(total / pageSize));

  function handleSortClick(col: TicketSortColumn) {
    if (sortBy === col) {
      onSortChange(col, sortDir === "asc" ? "desc" : "asc");
    } else {
      onSortChange(col, "asc");
    }
  }

  const thStyle: React.CSSProperties = {
    padding: "0.5rem 0.625rem",
    textAlign: "left",
    fontSize: "0.75rem",
    fontWeight: 700,
    textTransform: "uppercase",
    letterSpacing: "0.04em",
    color: "var(--color-text-muted)",
    borderBottom: "2px solid var(--color-border)",
    whiteSpace: "nowrap",
    cursor: "pointer",
    userSelect: "none",
  };
  const tdStyle: React.CSSProperties = {
    padding: "0.5rem 0.625rem",
    fontSize: "0.875rem",
    borderBottom: "1px solid var(--color-border)",
    verticalAlign: "middle",
  };

  return (
    <div data-testid="ticket-list-view" style={{ display: "flex", flexDirection: "column", gap: "0.75rem" }}>
      {loading && (
        <div
          role="status"
          aria-label="Loading tickets"
          data-testid="ticket-list-loading"
          style={{ color: "var(--color-text-muted)", fontSize: "0.875rem", padding: "0.5rem" }}
        >
          Loading tickets…
        </div>
      )}

      {!loading && tickets.length === 0 && (
        <div
          data-testid="ticket-list-empty"
          style={{
            padding: "2rem",
            textAlign: "center",
            color: "var(--color-text-muted)",
            fontSize: "0.9rem",
          }}
        >
          No tickets found matching your filters.
        </div>
      )}

      {!loading && tickets.length > 0 && (
        <div style={{ overflowX: "auto" }}>
          <table
            data-testid="ticket-list-table"
            style={{
              width: "100%",
              borderCollapse: "collapse",
              fontSize: "0.875rem",
            }}
          >
            <thead>
              <tr>
                {SORTABLE_COLUMNS.map(({ col, label }) => (
                  <th
                    key={col}
                    style={thStyle}
                    onClick={() => handleSortClick(col)}
                    data-testid={`sort-col-${col}`}
                    aria-sort={
                      sortBy === col
                        ? sortDir === "asc"
                          ? "ascending"
                          : "descending"
                        : "none"
                    }
                  >
                    {label}{" "}
                    <SortIndicator
                      col={col}
                      active={sortBy === col}
                      dir={sortDir}
                    />
                  </th>
                ))}
                <th style={thStyle}>Assignee</th>
                <th style={thStyle}>Team</th>
                <th style={thStyle}>RCDO</th>
                <th style={thStyle}>Target Week</th>
              </tr>
            </thead>
            <tbody>
              {tickets.map((ticket) => (
                <tr
                  key={ticket.id}
                  data-testid={`ticket-row-${ticket.id}`}
                  onClick={() => onSelectTicket(ticket.id)}
                  style={{
                    cursor: "pointer",
                    transition: "background 0.1s",
                  }}
                  onMouseEnter={(e) => {
                    (e.currentTarget as HTMLTableRowElement).style.background =
                      "var(--color-background)";
                  }}
                  onMouseLeave={(e) => {
                    (e.currentTarget as HTMLTableRowElement).style.background =
                      "";
                  }}
                >
                  <td style={tdStyle}>
                    <span
                      data-testid={`ticket-key-${ticket.id}`}
                      style={{ fontFamily: "monospace", fontSize: "0.8rem", fontWeight: 600 }}
                    >
                      {ticket.key}
                    </span>
                  </td>
                  <td style={{ ...tdStyle, maxWidth: "250px" }}>
                    <span
                      data-testid={`ticket-title-${ticket.id}`}
                      style={{
                        overflow: "hidden",
                        textOverflow: "ellipsis",
                        whiteSpace: "nowrap",
                        display: "block",
                      }}
                    >
                      {ticket.title}
                    </span>
                  </td>
                  <td style={tdStyle}>
                    <StatusBadge status={ticket.status} />
                  </td>
                  <td style={tdStyle}>
                    <PriorityBadge priority={ticket.priority} />
                  </td>
                  <td style={{ ...tdStyle, fontSize: "0.8rem", color: "var(--color-text-muted)" }}>
                    {new Date(ticket.updatedAt).toLocaleDateString()}
                  </td>
                  <td style={{ ...tdStyle, fontSize: "0.8rem" }}>
                    {ticket.assigneeUserId ?? (
                      <span style={{ color: "var(--color-text-muted)" }}>—</span>
                    )}
                  </td>
                  <td style={{ ...tdStyle, fontSize: "0.8rem" }}>
                    {ticket.teamId}
                  </td>
                  <td style={{ ...tdStyle, fontSize: "0.75rem", color: "var(--color-text-muted)" }}>
                    {ticket.rcdoNodeId
                      ? (rcdoLabels[ticket.rcdoNodeId] ?? ticket.rcdoNodeId)
                      : "—"}
                  </td>
                  <td style={{ ...tdStyle, fontSize: "0.8rem" }}>
                    {ticket.targetWeekStartDate ?? (
                      <span style={{ color: "var(--color-text-muted)" }}>—</span>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* Pagination */}
      {total > pageSize && (
        <div
          data-testid="ticket-list-pagination"
          style={{
            display: "flex",
            alignItems: "center",
            gap: "0.5rem",
            justifyContent: "flex-end",
            flexWrap: "wrap",
          }}
        >
          <span style={{ fontSize: "0.8rem", color: "var(--color-text-muted)" }}>
            {(page - 1) * pageSize + 1}–
            {Math.min(page * pageSize, total)} of {total}
          </span>
          <button
            type="button"
            onClick={() => onPageChange(page - 1)}
            disabled={page <= 1}
            data-testid="ticket-page-prev"
            style={{
              padding: "0.3rem 0.625rem",
              border: "1px solid var(--color-border)",
              borderRadius: "var(--border-radius)",
              background: "var(--color-surface)",
              cursor: page <= 1 ? "not-allowed" : "pointer",
              fontFamily: "inherit",
              fontSize: "0.8rem",
            }}
          >
            ◀ Prev
          </button>
          <span
            data-testid="ticket-page-indicator"
            style={{ fontSize: "0.8rem" }}
          >
            {page} / {totalPages}
          </span>
          <button
            type="button"
            onClick={() => onPageChange(page + 1)}
            disabled={page >= totalPages}
            data-testid="ticket-page-next"
            style={{
              padding: "0.3rem 0.625rem",
              border: "1px solid var(--color-border)",
              borderRadius: "var(--border-radius)",
              background: "var(--color-surface)",
              cursor: page >= totalPages ? "not-allowed" : "pointer",
              fontFamily: "inherit",
              fontSize: "0.8rem",
            }}
          >
            Next ▶
          </button>
        </div>
      )}
    </div>
  );
}

/**
 * TicketDetailView — full ticket detail panel.
 *
 * Shows:
 *   - Ticket key, title, status with transition buttons
 *   - Description
 *   - Priority, assignee, reporter, team, RCDO path, estimate, target week
 *   - Status history timeline
 *   - Linked commits list
 *   - Assignment change input
 */
import { useState, useCallback } from "react";
import type {
  TicketResponse,
  TicketStatus,
  TicketStatusHistory,
  LinkedCommitEntry,
} from "../../api/ticketTypes.js";
import type { CommitOutcome } from "../../api/planTypes.js";
import {
  TICKET_STATUS_LABELS,
  TICKET_STATUS_TRANSITIONS,
  TICKET_PRIORITY_LABELS,
} from "../../api/ticketTypes.js";

export interface TicketDetailViewProps {
  readonly ticket: TicketResponse;
  /** Called when status transition is requested. May throw to surface error. */
  readonly onStatusTransition: (ticketId: string, newStatus: TicketStatus) => Promise<void>;
  /** Called when assignee is changed. */
  readonly onAssigneeChange: (ticketId: string, assigneeUserId: string) => Promise<void>;
  /** Optional RCDO path label. */
  readonly rcdoPath?: string | undefined;
  readonly onClose?: () => void;
  readonly onEdit?: () => void;
}

const STATUS_COLORS: Record<TicketStatus, { bg: string; color: string }> = {
  TODO: { bg: "#f1f5f9", color: "#475569" },
  IN_PROGRESS: { bg: "#dbeafe", color: "#1e40af" },
  DONE: { bg: "#d1fae5", color: "#065f46" },
  CANCELED: { bg: "#f1f5f9", color: "#94a3b8" },
  BLOCKED: { bg: "#fee2e2", color: "#991b1b" },
};

const OUTCOME_LABELS: Record<CommitOutcome, string> = {
  ACHIEVED: "✓ Achieved",
  PARTIALLY_ACHIEVED: "◑ Partial",
  NOT_ACHIEVED: "✗ Not achieved",
  CANCELED: "— Canceled",
};
const OUTCOME_COLORS: Record<CommitOutcome, string> = {
  ACHIEVED: "var(--color-success)",
  PARTIALLY_ACHIEVED: "var(--color-warning)",
  NOT_ACHIEVED: "var(--color-danger)",
  CANCELED: "var(--color-text-muted)",
};

function StatusHistoryTimeline({
  history,
}: {
  readonly history: TicketStatusHistory[];
}) {
  if (history.length === 0) {
    return (
      <p
        data-testid="status-history-empty"
        style={{ fontSize: "0.875rem", color: "var(--color-text-muted)" }}
      >
        No status changes recorded.
      </p>
    );
  }

  return (
    <ol
      data-testid="status-history-timeline"
      style={{
        listStyle: "none",
        margin: 0,
        padding: 0,
        display: "flex",
        flexDirection: "column",
        gap: "0.5rem",
      }}
    >
      {[...history].reverse().map((entry) => (
        <li
          key={entry.id}
          data-testid={`history-entry-${entry.id}`}
          style={{
            display: "flex",
            alignItems: "flex-start",
            gap: "0.625rem",
            fontSize: "0.8rem",
          }}
        >
          <span
            style={{
              marginTop: "2px",
              width: "8px",
              height: "8px",
              borderRadius: "50%",
              background: "var(--color-primary)",
              flexShrink: 0,
            }}
          />
          <div>
            <span style={{ color: "var(--color-text-muted)" }}>
              {new Date(entry.changedAt).toLocaleString()}
            </span>{" "}
            —{" "}
            {entry.fromStatus ? (
              <>
                <strong>{TICKET_STATUS_LABELS[entry.fromStatus]}</strong>
                {" → "}
              </>
            ) : null}
            <strong>{TICKET_STATUS_LABELS[entry.toStatus]}</strong>
            {entry.note && (
              <span style={{ color: "var(--color-text-muted)" }}>
                {" "}({entry.note})
              </span>
            )}
          </div>
        </li>
      ))}
    </ol>
  );
}

function LinkedCommitsList({
  commits,
}: {
  readonly commits: LinkedCommitEntry[];
}) {
  if (commits.length === 0) {
    return (
      <p
        data-testid="linked-commits-empty"
        style={{ fontSize: "0.875rem", color: "var(--color-text-muted)" }}
      >
        No linked commits.
      </p>
    );
  }

  return (
    <ul
      data-testid="linked-commits-list"
      style={{
        listStyle: "none",
        margin: 0,
        padding: 0,
        display: "flex",
        flexDirection: "column",
        gap: "0.375rem",
      }}
    >
      {commits.map((c) => (
        <li
          key={c.commitId}
          data-testid={`linked-commit-${c.commitId}`}
          style={{
            background: "var(--color-background)",
            border: "1px solid var(--color-border)",
            borderRadius: "var(--border-radius)",
            padding: "0.5rem 0.75rem",
            fontSize: "0.85rem",
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center",
            flexWrap: "wrap",
            gap: "0.375rem",
          }}
        >
          <div>
            <span style={{ fontWeight: 600 }}>{c.commitTitle}</span>
            <span
              style={{
                marginLeft: "0.5rem",
                fontSize: "0.75rem",
                color: "var(--color-text-muted)",
              }}
            >
              {c.weekStartDate} · {c.chessPiece}
              {c.estimatePoints != null ? ` · ${c.estimatePoints}pts` : ""}
            </span>
          </div>
          {c.outcome && (
            <span
              data-testid={`linked-commit-outcome-${c.commitId}`}
              style={{
                fontSize: "0.75rem",
                color: OUTCOME_COLORS[c.outcome],
                fontWeight: 600,
              }}
            >
              {OUTCOME_LABELS[c.outcome]}
            </span>
          )}
        </li>
      ))}
    </ul>
  );
}

const sectionHeadingStyle: React.CSSProperties = {
  fontSize: "0.85rem",
  fontWeight: 700,
  textTransform: "uppercase",
  letterSpacing: "0.04em",
  color: "var(--color-text-muted)",
  margin: "0 0 0.5rem",
};

const metaRowStyle: React.CSSProperties = {
  display: "flex",
  gap: "0.375rem",
  fontSize: "0.875rem",
  alignItems: "baseline",
};

const metaLabelStyle: React.CSSProperties = {
  fontWeight: 600,
  minWidth: "100px",
  flexShrink: 0,
  color: "var(--color-text-muted)",
};

export function TicketDetailView({
  ticket,
  onStatusTransition,
  onAssigneeChange,
  rcdoPath,
  onClose,
  onEdit,
}: TicketDetailViewProps) {
  const [transitioning, setTransitioning] = useState<TicketStatus | null>(null);
  const [transitionError, setTransitionError] = useState<string | null>(null);
  const [assigneeInput, setAssigneeInput] = useState(ticket.assigneeUserId ?? "");
  const [assigneeSaving, setAssigneeSaving] = useState(false);
  const [assigneeError, setAssigneeError] = useState<string | null>(null);

  const nextStatuses = TICKET_STATUS_TRANSITIONS[ticket.status];

  const handleTransition = useCallback(
    async (newStatus: TicketStatus) => {
      setTransitioning(newStatus);
      setTransitionError(null);
      try {
        await onStatusTransition(ticket.id, newStatus);
      } catch (err) {
        setTransitionError(
          err instanceof Error ? err.message : "Status transition failed.",
        );
      } finally {
        setTransitioning(null);
      }
    },
    [ticket.id, onStatusTransition],
  );

  const handleAssigneeChange = useCallback(async () => {
    setAssigneeSaving(true);
    setAssigneeError(null);
    try {
      await onAssigneeChange(ticket.id, assigneeInput.trim());
    } catch (err) {
      setAssigneeError(
        err instanceof Error ? err.message : "Assignment change failed.",
      );
    } finally {
      setAssigneeSaving(false);
    }
  }, [ticket.id, assigneeInput, onAssigneeChange]);

  const { bg, color } = STATUS_COLORS[ticket.status];

  return (
    <div
      data-testid="ticket-detail-view"
      style={{
        background: "var(--color-surface)",
        border: "1px solid var(--color-border)",
        borderRadius: "var(--border-radius)",
        display: "flex",
        flexDirection: "column",
        gap: "1.25rem",
        overflow: "hidden",
      }}
    >
      {/* Header */}
      <div
        style={{
          padding: "1rem 1.25rem",
          borderBottom: "1px solid var(--color-border)",
          display: "flex",
          alignItems: "flex-start",
          justifyContent: "space-between",
          gap: "1rem",
          flexWrap: "wrap",
        }}
      >
        <div style={{ display: "flex", flexDirection: "column", gap: "0.375rem", flex: 1 }}>
          <div style={{ display: "flex", alignItems: "center", gap: "0.5rem", flexWrap: "wrap" }}>
            <span
              data-testid="ticket-detail-key"
              style={{
                fontFamily: "monospace",
                fontSize: "0.85rem",
                fontWeight: 700,
                color: "var(--color-text-muted)",
              }}
            >
              {ticket.key}
            </span>
            <span
              data-testid="ticket-detail-status-badge"
              style={{
                background: bg,
                color,
                padding: "2px 9px",
                borderRadius: "999px",
                fontSize: "0.75rem",
                fontWeight: 700,
              }}
            >
              {TICKET_STATUS_LABELS[ticket.status]}
            </span>
          </div>
          <h2
            data-testid="ticket-detail-title"
            style={{ margin: 0, fontSize: "1.1rem", fontWeight: 700 }}
          >
            {ticket.title}
          </h2>
        </div>

        {/* Action buttons */}
        <div style={{ display: "flex", gap: "0.5rem", flexShrink: 0 }}>
          {onEdit && (
            <button
              type="button"
              onClick={onEdit}
              data-testid="ticket-detail-edit-btn"
              style={{
                padding: "0.375rem 0.75rem",
                border: "1px solid var(--color-border)",
                borderRadius: "var(--border-radius)",
                background: "var(--color-surface)",
                cursor: "pointer",
                fontFamily: "inherit",
                fontSize: "0.8rem",
              }}
            >
              ✏ Edit
            </button>
          )}
          {onClose && (
            <button
              type="button"
              onClick={onClose}
              aria-label="Close ticket detail"
              data-testid="ticket-detail-close-btn"
              style={{
                padding: "0.375rem 0.5rem",
                border: "none",
                borderRadius: "var(--border-radius)",
                background: "none",
                cursor: "pointer",
                fontSize: "1rem",
                color: "var(--color-text-muted)",
              }}
            >
              ✕
            </button>
          )}
        </div>
      </div>

      <div style={{ padding: "0 1.25rem 1.25rem", display: "flex", flexDirection: "column", gap: "1.25rem" }}>
        {/* Status transitions */}
        {nextStatuses.length > 0 && (
          <div>
            <p style={sectionHeadingStyle}>Status Transitions</p>
            <div
              data-testid="status-transition-buttons"
              style={{ display: "flex", gap: "0.375rem", flexWrap: "wrap" }}
            >
              {nextStatuses.map((next) => (
                <button
                  key={next}
                  type="button"
                  onClick={() => void handleTransition(next)}
                  disabled={transitioning !== null}
                  data-testid={`transition-btn-${next.toLowerCase()}`}
                  style={{
                    padding: "0.375rem 0.875rem",
                    border: "1px solid var(--color-border)",
                    borderRadius: "var(--border-radius)",
                    background: STATUS_COLORS[next].bg,
                    color: STATUS_COLORS[next].color,
                    cursor: transitioning !== null ? "not-allowed" : "pointer",
                    fontFamily: "inherit",
                    fontSize: "0.8rem",
                    fontWeight: 600,
                  }}
                >
                  {transitioning === next
                    ? "…"
                    : `→ ${TICKET_STATUS_LABELS[next]}`}
                </button>
              ))}
            </div>
            {transitionError && (
              <span
                data-testid="transition-error"
                role="alert"
                style={{ fontSize: "0.8rem", color: "var(--color-danger)", marginTop: "0.375rem", display: "block" }}
              >
                {transitionError}
              </span>
            )}
          </div>
        )}

        {/* Description */}
        {ticket.description && (
          <div>
            <p style={sectionHeadingStyle}>Description</p>
            <p
              data-testid="ticket-detail-description"
              style={{ margin: 0, fontSize: "0.875rem", lineHeight: 1.6 }}
            >
              {ticket.description}
            </p>
          </div>
        )}

        {/* Metadata */}
        <div>
          <p style={sectionHeadingStyle}>Details</p>
          <div
            data-testid="ticket-detail-meta"
            style={{ display: "flex", flexDirection: "column", gap: "0.375rem" }}
          >
            <div style={metaRowStyle}>
              <span style={metaLabelStyle}>Priority</span>
              <span data-testid="ticket-detail-priority">
                {TICKET_PRIORITY_LABELS[ticket.priority]}
              </span>
            </div>
            <div style={metaRowStyle}>
              <span style={metaLabelStyle}>Reporter</span>
              <span data-testid="ticket-detail-reporter">{ticket.reporterUserId}</span>
            </div>
            <div style={metaRowStyle}>
              <span style={metaLabelStyle}>Team</span>
              <span data-testid="ticket-detail-team">{ticket.teamId}</span>
            </div>
            {ticket.rcdoNodeId && (
              <div style={metaRowStyle}>
                <span style={metaLabelStyle}>RCDO</span>
                <span data-testid="ticket-detail-rcdo">
                  {rcdoPath ?? ticket.rcdoNodeId}
                </span>
              </div>
            )}
            {ticket.estimatePoints != null && (
              <div style={metaRowStyle}>
                <span style={metaLabelStyle}>Estimate</span>
                <span data-testid="ticket-detail-estimate">
                  {ticket.estimatePoints} pts
                </span>
              </div>
            )}
            {ticket.targetWeekStartDate && (
              <div style={metaRowStyle}>
                <span style={metaLabelStyle}>Target Week</span>
                <span data-testid="ticket-detail-target-week">
                  {ticket.targetWeekStartDate}
                </span>
              </div>
            )}
            <div style={metaRowStyle}>
              <span style={metaLabelStyle}>Created</span>
              <span>{new Date(ticket.createdAt).toLocaleString()}</span>
            </div>
          </div>
        </div>

        {/* Assignment change */}
        <div>
          <p style={sectionHeadingStyle}>Assignment</p>
          <div
            data-testid="ticket-assignment-section"
            style={{ display: "flex", gap: "0.5rem", alignItems: "center", flexWrap: "wrap" }}
          >
            <input
              type="text"
              value={assigneeInput}
              onChange={(e) => setAssigneeInput(e.target.value)}
              placeholder="User ID (leave blank to unassign)"
              data-testid="ticket-assignee-input"
              style={{
                padding: "0.4rem 0.625rem",
                border: "1px solid var(--color-border)",
                borderRadius: "var(--border-radius)",
                background: "var(--color-surface)",
                color: "var(--color-text)",
                fontFamily: "inherit",
                fontSize: "0.875rem",
                minWidth: "180px",
              }}
            />
            <button
              type="button"
              onClick={() => void handleAssigneeChange()}
              disabled={assigneeSaving}
              data-testid="ticket-assign-save-btn"
              style={{
                padding: "0.4rem 0.875rem",
                border: "none",
                borderRadius: "var(--border-radius)",
                background: "var(--color-primary)",
                color: "#fff",
                cursor: assigneeSaving ? "not-allowed" : "pointer",
                fontFamily: "inherit",
                fontSize: "0.875rem",
                fontWeight: 600,
              }}
            >
              {assigneeSaving ? "Saving…" : "Update"}
            </button>
          </div>
          {assigneeError && (
            <span
              data-testid="assignee-error"
              role="alert"
              style={{ fontSize: "0.8rem", color: "var(--color-danger)", marginTop: "0.375rem", display: "block" }}
            >
              {assigneeError}
            </span>
          )}
        </div>

        {/* Status history */}
        <div>
          <p style={sectionHeadingStyle}>Status History</p>
          <StatusHistoryTimeline history={ticket.statusHistory} />
        </div>

        {/* Linked commits */}
        <div>
          <p style={sectionHeadingStyle}>Linked Commits</p>
          <LinkedCommitsList commits={ticket.linkedCommits} />
        </div>
      </div>
    </div>
  );
}

package com.weeklycommit.domain.enums;

public enum TicketStatus {
	BACKLOG, READY, IN_PROGRESS, BLOCKED, DONE, CANCELED
}

package com.weeklycommit.domain.entity;

import com.weeklycommit.domain.enums.TicketStatus;
import jakarta.persistence.Column;
import jakarta.persistence.Entity;
import jakarta.persistence.EnumType;
import jakarta.persistence.Enumerated;
import jakarta.persistence.GeneratedValue;
import jakarta.persistence.GenerationType;
import jakarta.persistence.Id;
import jakarta.persistence.Table;
import jakarta.validation.constraints.NotBlank;
import jakarta.validation.constraints.NotNull;
import java.time.Instant;
import java.time.LocalDate;
import java.util.UUID;
import org.hibernate.annotations.CreationTimestamp;
import org.hibernate.annotations.UpdateTimestamp;

@Entity
@Table(name = "work_item")
public class WorkItem {

	@Id
	@GeneratedValue(strategy = GenerationType.UUID)
	@Column(nullable = false, updatable = false)
	private UUID id;

	@NotNull
	@Column(name = "team_id", nullable = false)
	private UUID teamId;

	@NotBlank
	@Column(nullable = false)
	private String key;

	@NotBlank
	@Column(nullable = false)
	private String title;

	@Column
	private String description;

	@NotNull
	@Enumerated(EnumType.STRING)
	@Column(nullable = false)
	private TicketStatus status = TicketStatus.BACKLOG;

	@Column(name = "assignee_user_id")
	private UUID assigneeUserId;

	@NotNull
	@Column(name = "reporter_user_id", nullable = false)
	private UUID reporterUserId;

	@Column(name = "estimate_points")
	private Integer estimatePoints;

	@Column(name = "rcdo_node_id")
	private UUID rcdoNodeId;

	@Column(name = "target_week_start_date")
	private LocalDate targetWeekStartDate;

	@CreationTimestamp
	@Column(name = "created_at", nullable = false, updatable = false)
	private Instant createdAt;

	@UpdateTimestamp
	@Column(name = "updated_at", nullable = false)
	private Instant updatedAt;

	public UUID getId() {
		return id;
	}

	public void setId(UUID id) {
		this.id = id;
	}

	public UUID getTeamId() {
		return teamId;
	}

	public void setTeamId(UUID teamId) {
		this.teamId = teamId;
	}

	public String getKey() {
		return key;
	}

	public void setKey(String key) {
		this.key = key;
	}

	public String getTitle() {
		return title;
	}

	public void setTitle(String title) {
		this.title = title;
	}

	public String getDescription() {
		return description;
	}

	public void setDescription(String description) {
		this.description = description;
	}

	public TicketStatus getStatus() {
		return status;
	}

	public void setStatus(TicketStatus status) {
		this.status = status;
	}

	public UUID getAssigneeUserId() {
		return assigneeUserId;
	}

	public void setAssigneeUserId(UUID assigneeUserId) {
		this.assigneeUserId = assigneeUserId;
	}

	public UUID getReporterUserId() {
		return reporterUserId;
	}

	public void setReporterUserId(UUID reporterUserId) {
		this.reporterUserId = reporterUserId;
	}

	public Integer getEstimatePoints() {
		return estimatePoints;
	}

	public void setEstimatePoints(Integer estimatePoints) {
		this.estimatePoints = estimatePoints;
	}

	public UUID getRcdoNodeId() {
		return rcdoNodeId;
	}

	public void setRcdoNodeId(UUID rcdoNodeId) {
		this.rcdoNodeId = rcdoNodeId;
	}

	public LocalDate getTargetWeekStartDate() {
		return targetWeekStartDate;
	}

	public void setTargetWeekStartDate(LocalDate targetWeekStartDate) {
		this.targetWeekStartDate = targetWeekStartDate;
	}

	public Instant getCreatedAt() {
		return createdAt;
	}

	public Instant getUpdatedAt() {
		return updatedAt;
	}
}

package com.weeklycommit.ticket.service;

import com.weeklycommit.domain.entity.WorkItem;
import com.weeklycommit.domain.entity.WorkItemStatusHistory;
import com.weeklycommit.domain.enums.TicketStatus;
import com.weeklycommit.domain.repository.WorkItemRepository;
import com.weeklycommit.domain.repository.WorkItemStatusHistoryRepository;
import com.weeklycommit.plan.exception.PlanValidationException;
import com.weeklycommit.rcdo.exception.ResourceNotFoundException;
import com.weeklycommit.ticket.dto.CreateTicketRequest;
import com.weeklycommit.ticket.dto.TicketResponse;
import com.weeklycommit.ticket.dto.TicketStatusHistoryResponse;
import com.weeklycommit.ticket.dto.UpdateTicketRequest;
import java.util.EnumSet;
import java.util.List;
import java.util.Map;
import java.util.Set;
import java.util.UUID;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

/**
 * CRUD and status-workflow service for native tickets (work items).
 *
 * <p>
 * Status transitions are enforced via a static transition map. Every status
 * change is appended to {@code work_item_status_history} for duration-in-status
 * reporting.
 */
@Service
@Transactional
public class TicketService {

	/** Valid Fibonacci-scale estimate values (mirrors CommitService). */
	private static final Set<Integer> VALID_ESTIMATE_POINTS = Set.of(1, 2, 3, 5, 8);

	/** Key prefix used when auto-generating ticket keys. */
	private static final String KEY_PREFIX = "T-";

	/**
	 * Legal status transitions.
	 *
	 * <pre>
	 * BACKLOG     → READY, IN_PROGRESS, CANCELED
	 * READY       → IN_PROGRESS, BACKLOG, CANCELED
	 * IN_PROGRESS → DONE, BLOCKED, READY, CANCELED
	 * BLOCKED     → IN_PROGRESS, CANCELED
	 * DONE        → (terminal)
	 * CANCELED    → (terminal)
	 * </pre>
	 */
	private static final Map<TicketStatus, Set<TicketStatus>> ALLOWED_TRANSITIONS = Map.of(TicketStatus.BACKLOG,
			EnumSet.of(TicketStatus.READY, TicketStatus.IN_PROGRESS, TicketStatus.CANCELED), TicketStatus.READY,
			EnumSet.of(TicketStatus.IN_PROGRESS, TicketStatus.BACKLOG, TicketStatus.CANCELED), TicketStatus.IN_PROGRESS,
			EnumSet.of(TicketStatus.DONE, TicketStatus.BLOCKED, TicketStatus.READY, TicketStatus.CANCELED),
			TicketStatus.BLOCKED, EnumSet.of(TicketStatus.IN_PROGRESS, TicketStatus.CANCELED), TicketStatus.DONE,
			EnumSet.noneOf(TicketStatus.class), TicketStatus.CANCELED, EnumSet.noneOf(TicketStatus.class));

	private final WorkItemRepository workItemRepo;
	private final WorkItemStatusHistoryRepository historyRepo;

	public TicketService(WorkItemRepository workItemRepo, WorkItemStatusHistoryRepository historyRepo) {
		this.workItemRepo = workItemRepo;
		this.historyRepo = historyRepo;
	}

	// -------------------------------------------------------------------------
	// Create
	// -------------------------------------------------------------------------

	/**
	 * Creates a new ticket with an auto-generated key of the form {@code T-N}.
	 *
	 * @param req
	 *            creation request
	 * @return saved ticket
	 */
	public TicketResponse createTicket(CreateTicketRequest req) {
		validateEstimatePoints(req.estimatePoints());

		WorkItem item = new WorkItem();
		item.setTeamId(req.teamId());
		item.setKey(generateKey(req.teamId()));
		item.setTitle(req.title());
		item.setDescription(req.description());
		item.setStatus(TicketStatus.BACKLOG);
		item.setAssigneeUserId(req.assigneeUserId());
		item.setReporterUserId(req.reporterUserId());
		item.setEstimatePoints(req.estimatePoints());
		item.setRcdoNodeId(req.rcdoNodeId());
		item.setTargetWeekStartDate(req.targetWeekStartDate());

		return TicketResponse.from(workItemRepo.save(item));
	}

	// -------------------------------------------------------------------------
	// Read
	// -------------------------------------------------------------------------

	/**
	 * Fetches a single ticket by its ID.
	 *
	 * @param id
	 *            ticket identifier
	 * @return ticket view
	 * @throws ResourceNotFoundException
	 *             if not found
	 */
	@Transactional(readOnly = true)
	public TicketResponse getTicket(UUID id) {
		return TicketResponse.from(requireTicket(id));
	}

	/**
	 * Lists all tickets for a team.
	 *
	 * @param teamId
	 *            team identifier
	 * @return list of ticket views
	 */
	@Transactional(readOnly = true)
	public List<TicketResponse> listTicketsByTeam(UUID teamId) {
		return workItemRepo.findByTeamId(teamId).stream().map(TicketResponse::from).toList();
	}

	// -------------------------------------------------------------------------
	// Update
	// -------------------------------------------------------------------------

	/**
	 * Partially updates a ticket. {@code null} fields in the request are ignored.
	 *
	 * @param id
	 *            ticket identifier
	 * @param req
	 *            partial update
	 * @return updated ticket view
	 */
	public TicketResponse updateTicket(UUID id, UpdateTicketRequest req) {
		WorkItem item = requireTicket(id);

		if (req.title() != null && !req.title().isBlank()) {
			item.setTitle(req.title());
		}
		if (req.description() != null) {
			item.setDescription(req.description());
		}
		if (req.assigneeUserId() != null) {
			item.setAssigneeUserId(req.assigneeUserId());
		}
		if (req.estimatePoints() != null) {
			validateEstimatePoints(req.estimatePoints());
			item.setEstimatePoints(req.estimatePoints());
		}
		if (req.rcdoNodeId() != null) {
			item.setRcdoNodeId(req.rcdoNodeId());
		}
		if (req.targetWeekStartDate() != null) {
			item.setTargetWeekStartDate(req.targetWeekStartDate());
		}

		return TicketResponse.from(workItemRepo.save(item));
	}

	// -------------------------------------------------------------------------
	// Update status
	// -------------------------------------------------------------------------

	/**
	 * Transitions the ticket to a new status, validating the transition and
	 * recording history.
	 *
	 * @param id
	 *            ticket identifier
	 * @param newStatus
	 *            target status
	 * @param changedByUserId
	 *            user performing the transition
	 * @return updated ticket view
	 * @throws PlanValidationException
	 *             if the transition is not allowed
	 */
	public TicketResponse updateStatus(UUID id, TicketStatus newStatus, UUID changedByUserId) {
		WorkItem item = requireTicket(id);
		TicketStatus currentStatus = item.getStatus();

		if (currentStatus == newStatus) {
			return TicketResponse.from(item); // idempotent — no change
		}

		Set<TicketStatus> allowed = ALLOWED_TRANSITIONS.getOrDefault(currentStatus, EnumSet.noneOf(TicketStatus.class));
		if (!allowed.contains(newStatus)) {
			throw new PlanValidationException(
					"Illegal ticket status transition: " + currentStatus + " → " + newStatus + ". Allowed: " + allowed);
		}

		// Record history before updating the entity
		WorkItemStatusHistory history = new WorkItemStatusHistory();
		history.setWorkItemId(id);
		history.setFromStatus(currentStatus.name());
		history.setToStatus(newStatus.name());
		history.setChangedByUserId(changedByUserId);
		historyRepo.save(history);

		item.setStatus(newStatus);
		return TicketResponse.from(workItemRepo.save(item));
	}

	// -------------------------------------------------------------------------
	// Status history
	// -------------------------------------------------------------------------

	/**
	 * Returns the full status-change history for a ticket, ordered chronologically.
	 *
	 * @param id
	 *            ticket identifier
	 * @return ordered list of status history entries
	 */
	@Transactional(readOnly = true)
	public List<TicketStatusHistoryResponse> getStatusHistory(UUID id) {
		requireTicket(id); // ensure ticket exists
		return historyRepo.findByWorkItemIdOrderByCreatedAtAsc(id).stream().map(TicketStatusHistoryResponse::from)
				.toList();
	}

	// -------------------------------------------------------------------------
	// Delete
	// -------------------------------------------------------------------------

	/**
	 * Hard-deletes a ticket.
	 *
	 * @param id
	 *            ticket identifier
	 * @throws ResourceNotFoundException
	 *             if not found
	 */
	public void deleteTicket(UUID id) {
		WorkItem item = requireTicket(id);
		workItemRepo.delete(item);
	}

	// -------------------------------------------------------------------------
	// Private helpers
	// -------------------------------------------------------------------------

	WorkItem requireTicket(UUID id) {
		return workItemRepo.findById(id).orElseThrow(() -> new ResourceNotFoundException("Ticket not found: " + id));
	}

	/**
	 * Generates a unique key for a ticket within its team. Uses a simple sequential
	 * counter based on the total number of tickets in the team.
	 */
	private String generateKey(UUID teamId) {
		long count = workItemRepo.countByTeamId(teamId);
		return KEY_PREFIX + (count + 1);
	}

	static void validateEstimatePoints(Integer points) {
		if (points != null && !VALID_ESTIMATE_POINTS.contains(points)) {
			throw new PlanValidationException("Estimate points must be one of {1, 2, 3, 5, 8}, got: " + points);
		}
	}
}

